CREATE DATABASE IF NOT EXISTS brutemode CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci;
USE brutemode;
CREATE TABLE IF NOT EXISTS users (id INT AUTO_INCREMENT PRIMARY KEY, email VARCHAR(190) UNIQUE, password VARCHAR(255), name VARCHAR(120), weight DECIMAL(6,2) DEFAULT NULL, goal VARCHAR(255) DEFAULT NULL, profile_pic VARCHAR(255) DEFAULT NULL, rank VARCHAR(40) DEFAULT 'Recruit', points INT DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS workouts (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT, date DATE, notes TEXT DEFAULT NULL, total_volume DECIMAL(12,2) DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, INDEX(user_id));
CREATE TABLE IF NOT EXISTS exercises (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(160), muscle_group VARCHAR(80), is_custom TINYINT(1) DEFAULT 0, user_id INT DEFAULT NULL, is_favorite TINYINT(1) DEFAULT 0, INDEX(user_id));
CREATE TABLE IF NOT EXISTS workout_exercises (id INT AUTO_INCREMENT PRIMARY KEY, workout_id INT, exercise_id INT);
CREATE TABLE IF NOT EXISTS sets (id INT AUTO_INCREMENT PRIMARY KEY, workout_exercise_id INT, reps INT, weight DECIMAL(8,2));
CREATE TABLE IF NOT EXISTS badges (id INT AUTO_INCREMENT PRIMARY KEY, code VARCHAR(80) UNIQUE, name VARCHAR(120), tier VARCHAR(20), icon VARCHAR(40), description VARCHAR(255));
CREATE TABLE IF NOT EXISTS user_badges (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT, badge_id INT, unlocked_at DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uniq_user_badge(user_id,badge_id));
CREATE TABLE IF NOT EXISTS user_points (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT, points INT, reason VARCHAR(80), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, INDEX(user_id));
CREATE TABLE IF NOT EXISTS body_logs (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT, date DATE, weight DECIMAL(6,2) DEFAULT NULL, neck DECIMAL(6,2) DEFAULT NULL, chest DECIMAL(6,2) DEFAULT NULL, waist DECIMAL(6,2) DEFAULT NULL, hips DECIMAL(6,2) DEFAULT NULL, arm DECIMAL(6,2) DEFAULT NULL, thigh DECIMAL(6,2) DEFAULT NULL, photo_path VARCHAR(255) DEFAULT NULL, INDEX(user_id,date));
CREATE TABLE IF NOT EXISTS habits (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT, date DATE, water_ml INT DEFAULT 0, sleep_hours DECIMAL(4,2) DEFAULT 0, protein_g INT DEFAULT 0, INDEX(user_id,date));
